return Builder(builder: (context) {
  return Align(
    alignment: Alignment.center,
    child: ElevatedButton.icon(
      icon: const Icon(Icons.add_card, size: 20),
      label: const Text(
        "Add New Transaction", 
        style: TextStyle(fontSize: 14, fontWeight: FontWeight.w600, letterSpacing: 0.3)
      ),
      onPressed: () async {
        final newComp = getOne();
        if (newComp != null) {
          String? errorMessage;
          final result = await showDialog<bool>(
            context: context,
            builder: (context) => StatefulBuilder(
              builder: (context, setModalState) => AlertDialog(
                title: const Text("Add New Transaction", style: TextStyle(color: Color(0xFF2E7D32), fontWeight: FontWeight.bold)),
                content: SingleChildScrollView(
                  child: SizedBox(
                    width: double.maxFinite,
                    child: Column(
                      mainAxisSize: MainAxisSize.min,
                      children: [
                        if (errorMessage != null)
                          Container(
                            padding: const EdgeInsets.all(20),
                            margin: const EdgeInsets.only(bottom: 16),
                            decoration: BoxDecoration(
                              border: Border.all(color: Colors.red, width: 4),
                              borderRadius: BorderRadius.circular(8),
                            ),
                            child: Text(
                              errorMessage!,
                              style: const TextStyle(color: Colors.red, fontWeight: FontWeight.bold),
                            ),
                          ),
                        newComp.editor(
                          key: const ValueKey("modal_add_tx"),
                          onChanged: (val) {},
                          cbNotifyParent: (notifier, data, observers) {
                            setModalState(() {
                              updateObservers(notifier, data, observers, newComp);
                            });
                          },
                        ),
                      ],
                    ),
                  ),
                ),
                actions: [
                  TextButton(onPressed: () => Navigator.pop(context, false), child: const Text("CANCEL")),
