Widget _buildAddButton(BuildContext context) {
  return Align(
    alignment: Alignment.center,
    child: ElevatedButton.icon(
      icon: const Icon(Icons.add_circle_outline_rounded, size: 18),
      label: const Text(
        "Add New Transaction", 
        style: TextStyle(fontSize: 13, fontWeight: FontWeight.w600, letterSpacing: 0.2)
      ),
      onPressed: () async {
        final newComp = widget.account.getOne();
        if (newComp != null) {
          String? errorMessage;
          final result = await showDialog<bool>(
            context: context,
            builder: (context) => StatefulBuilder(
              builder: (context, setModalState) => AlertDialog(
                title: const Text("Add New Transaction", style: TextStyle(color: Color(0xFF2E7D32), fontWeight: FontWeight.bold)),
                content: SingleChildScrollView(
                  child: SizedBox(
                    width: double.maxFinite,
                    child: Column(
                      mainAxisSize: MainAxisSize.min,
                      children: [
                        if (errorMessage != null)
                          Container(
                            padding: const EdgeInsets.all(20),
                            margin: const EdgeInsets.only(bottom: 16),
                            decoration: BoxDecoration(
                              border: Border.all(color: Colors.red, width: 4),
                              borderRadius: BorderRadius.circular(8),
                            ),
                            child: Text(
                              errorMessage!,
                              style: const TextStyle(color: Colors.red, fontWeight: FontWeight.bold),
                            ),
                          ),
                        newComp.editor(
                          key: const ValueKey("modal_add_tx"),
                          onChanged: (val) {},
                          cbNotifyParent: (notifier, data, observers) {
                            setModalState(() {
                              widget.account.updateObservers(notifier, data, observers, newComp);
                            });
                          },
                        ),
                      ],
                    ),
                  ),
                ),
                actions: [
                  TextButton(
                    onPressed: () => Navigator.pop(context, false),
                    child: const Text("CANCEL", style: TextStyle(color: Colors.grey, fontWeight: FontWeight.w600)),
                  ),
                  TextButton(
                    onPressed: () {
                      final v = widget.account._validateOne(newComp);
                      if (v['valid'] == true) {
                        Navigator.pop(context, true);
                      } else {
                        setModalState(() {
                          errorMessage = v['constraint'];
                        });
                      }
                    },
                    child: const Text("ADD", style: TextStyle(color: Color(0xFF2E7D32), fontWeight: FontWeight.bold)),
                  ),
                ],
              ),
            ),
          );

          if (result == true) {
            setState(() {
              widget.account.componentsArray.insert(0, newComp);
              widget.account.fetch();
            });
            widget.onChanged(widget.account.fetch());
          }
        }
      },
      style: ElevatedButton.styleFrom(
        backgroundColor: const Color(0xFF2E7D32),
        foregroundColor: Colors.white,
        elevation: 1,
        padding: const EdgeInsets.symmetric(vertical: 10, horizontal: 20),
        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(24)),
      ),
    ),
  );
}

