class _CompositeEditorState extends State<_CompositeEditor> {
  bool _isAllNumber(List<GenInterface> group) {
    if (group.isEmpty) return false;
    return group.every((c) => c.getType() == "number");
  }

  bool _isLongField(GenInterface c) {
    final name = c.getName().toLowerCase();
    if (name.contains("address") ||
        name.contains("notes") ||
        name.contains("remark") ||
        name.contains("description")) {
      return true;
    }
    try {
      if ((c as dynamic).multiline == true) {
        return true;
      }
    } catch (_) {}
    return false;
  }

  List<List<GenInterface>> _processGroups(List<List<GenInterface>> originalGroups) {
    List<List<GenInterface>> processed = [];
    for (var group in originalGroups) {
      if (group.length <= 1) {
        processed.add(group);
      } else {
        List<GenInterface> currentRow = [];
        for (var c in group) {
          if (_isLongField(c)) {
            if (currentRow.isNotEmpty) {
              processed.add(currentRow);
              currentRow = [];
            }
            processed.add([c]);
          } else {
            currentRow.add(c);
          }
        }
        if (currentRow.isNotEmpty) {
          processed.add(currentRow);
        }
      }
    }
    return processed;
  }

  @override
  Widget build(BuildContext context) {
    final processedGroups = _processGroups(widget.groups);

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Padding(
          padding: const EdgeInsets.symmetric(horizontal: 8.0),
          child: Text(
            widget.label,
            style: Theme.of(context).textTheme.titleMedium,
          ),
        ),
        ...processedGroups.map((group) {
          final useRowLayout = processedGroups.length > 1 || _isAllNumber(group);
          return Column(
            children: [
              if (useRowLayout)
                Row(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: group
                      .map(
                        (c) => Expanded(
                          child: c.editor(
                            key: ValueKey(c.getName()),
                            onChanged: (val) => widget.onChanged(),
                            cbNotifyParent: (notifier, data, observers) {
                              List<int> observerIndexes = widget.composite
                                  .getObserverComponentIndexes(notifier);

                              if (widget.cbNotifyParent != null) {
                                widget.cbNotifyParent!(
                                  notifier,
                                  data,
                                  observerIndexes,
                                );
                              } else {
                                for (var idx in observerIndexes) {
                                  final obsComp = widget.composite
                                      .getComponentAtIndex(idx);
                                  obsComp?.notify({
                                    "notifier": data,
                                    "loading": false,
                                  });
                                }
                              }

                              setState(() {});
                              widget.onChanged();
                            },
                            frefs: widget.frefs,
                            index: widget.index,
                            autoFocus: widget.autoFocus,
                            refresh: widget.refresh,
                          ),
                        ),
                      )
                      .toList(),
                )
              else
                Wrap(
